// CRC16-CCITT-FALSE 实现
function crc16Ccitt(str) {
    let crc = 0xFFFF;
    const poly = 0x1021;

    for (let i = 0; i < str.length; i++) {
        crc ^= (str.charCodeAt(i) << 8);
        for (let j = 0; j < 8; j++) {
            if (crc & 0x8000) {
                crc = (crc << 1) ^ poly;
            } else {
                crc <<= 1;
            }
            crc &= 0xFFFF; // 保持16位
        }
    }
    return crc;
}

// 处理所有输入数据
return $input.all().map(item => {
    const data = item.json;
    const uuid = data.uuid;
    const base64Token = data["Base64-encoded Token"];

    // 计算CRC16
    const uuidCrc = crc16Ccitt(uuid);
    const tokenCrc = crc16Ccitt(base64Token);

    // 返回结果，确保CRC16值是4个字符长
    return {
        json: {
            uuid_apple: uuid,
            base64Token: base64Token,
            uuidCrc: uuidCrc.toString(16).padStart(4, '0').toUpperCase(),
            tokenCrc: tokenCrc.toString(16).padStart(4, '0').toUpperCase()
        }
    };
});

