const inputItems = $('Webhook').all(); // 获取所有输入项

// 函数：根据 sn 前缀获取相应的 ppid
function getPPID(sn) {
    const snToPpidMap = {
        "W92": "828649-509327",
        "W51": "828649-833829",
        "W52": "828649-814264"
    };

    const prefix = sn.substring(0, 3); // 提取前3个字符
    return snToPpidMap.hasOwnProperty(prefix) ? snToPpidMap[prefix] : "未找到对应的ppid";
}

let results = [];

// 遍历每一个 input 项
inputItems.forEach(item => {
    if (item.json && item.json.body && item.json.body.sn) {
        const sn = item.json.body.sn; // 从 json.body 中提取 sn
        const ppid = getPPID(sn);

        results.push({
            json: {
                sn: sn,
                ppid: ppid
            }
        });
    }
});

return results;

// 你的输入数据节点
const originalDataNode = $input.all();

// 检查输入数据的有效性
if (!originalDataNode.length) {
    throw new Error("No valid original data found in originalDataNode");
}

// 创建一个对象，以token为键，UUID为值
const authEntitiesMapping = originalDataNode.reduce((acc, dataNode) => {
    const token = dataNode.json.token;
    const uuid = dataNode.json.uuid;
    acc[token] = uuid;
    return acc;
}, {});

// 提取 ppid（假设所有数据项的 ppid 相同，用第一个）
const resultPpid = originalDataNode[0].json.ppid;

// 构建最终结果对象
const result = {
    ppid: resultPpid,
    auth_entities: [authEntitiesMapping] // 将对象放在数组中
};

// 返回结果
return {
    json: result
};

